arguments.command:
# Try nm to find symbols near these addresses using the full debug file
# The text section end is around 0x2ef810; 0x2f4b20 is past it - possibly in data
# Let's check with nm for the nearest function symbols below these addresses
aarch64-linux-gnu-nm -n -C /tmp/libmonosgen_debug.so 2>/dev/null | awk '
  /^[0-9a-f]+ [tTwW]/ {
    addr = strtonum("0x"$1); name = $3;
    for (i=4; i<=NF; i++) name = name " " $i;
    if (addr <= 0x2f4b20) { f1_addr = $1; f1_name = name }
    if (addr <= 0x2f4c84) { f2_addr = $1; f2_name = name }
  }
  END {
    print "Nearest to 0x2f4b20: " f1_addr " " f1_name
    print "Nearest to 0x2f4c84: " f2_addr " " f2_name
  }'

