{"command": "# Verify using the stripped binary's segments
aarch64-linux-gnu-readelf -l /tmp/libmonosgen.so | grep -A2 LOAD
echo "==="
# The addresses in the SGen worker are in BSS/data, meaning the unwinder failed
# Let me verify what's at those BSS offsets - they're likely in the interpreter label table
aarch64-linux-gnu-nm -n -C /tmp/libmonosgen_debug.so 2>/dev/null | awk '
  strtonum("0x"$1) <= 0x2f4b20 && strtonum("0x"$1) >= 0x2f4000 { last = $0 }
  strtonum("0x"$1) > 0x2f4b20 && !found1 { print "0x2f4b20 falls after: " last; print "  and before: " $0; found1=1 }
' | head -4
echo "---"
aarch64-linux-gnu-nm -n -C /tmp/libmonosgen_debug.so 2>/dev/null | awk '
  strtonum("0x"$1) <= 0x2f4c84 && strtonum("0x"$1) >= 0x2f4000 { last = $0 }
  strtonum("0x"$1) > 0x2f4c84 && !found1 { print "0x2f4c84 falls after: " last; print "  and before: " $0; found1=1 }
' | head -4", "description": "Verify unresolvable SGen worker addresses", "initial_wait": 15}
